class InteractiveVisualizerEngine {
  constructor() {
    this.currentStep = 0;
    this.totalSteps = 5;
    this.timer = null;
    this.speed = 1000;
    this.path = 'GET /';
  }
  init() {
    this.render();
  }
  generateSteps() {
    return [
      { step: 0, line: 5, status: 'Client gửi HTTP Request', desc: 'Client gửi yêu cầu ' + this.path + ' tới server.' },
      { step: 1, line: 5, status: 'Uvicorn tiếp nhận', desc: 'Uvicorn ASGI Server nhận socket connection trên port 8000.' },
      { step: 2, line: 1, status: 'Chuyển tiếp tới FastAPI', desc: 'Uvicorn gọi ASGI app instance (app = FastAPI()).' },
      { step: 3, line: 2, status: 'Khớp Route Decorator', desc: 'FastAPI tìm kiếm route khớp với path ' + this.path + ' (@app.get("/")).' },
      { step: 4, line: 3, status: 'Thực thi Path Operation', desc: 'Hàm root() được gọi và trả về dictionary Python.' },
      { step: 5, line: 4, status: 'Trả về HTTP Response', desc: 'FastAPI serialize dict thành JSON và Uvicorn gửi HTTP 200 OK về Client.' }
    ];
  }
  render() {
    const steps = this.generateSteps();
    const cur = steps[this.currentStep];
    this.highlightCode(cur.line);
    this.updateStats(this.currentStep, cur.status);
    this.log(cur.desc, 'info');
  }
  highlightCode(lineNum) {
    for (let i = 0; i <= 5; i++) {
      const el = document.getElementById('line-' + i);
      if (el) {
        if (i === lineNum) el.style.backgroundColor = '#fef08a';
        else el.style.backgroundColor = 'transparent';
      }
    }
  }
  updateStats(step, status) {
    const sEl = document.getElementById('stat-step');
    const stEl = document.getElementById('stat-status');
    if (sEl) sEl.innerText = step + '/' + this.totalSteps;
    if (stEl) stEl.innerText = status;
  }
  log(msg, type) {
    console.log('[' + type.toUpperCase() + '] ' + msg);
  }
  start() {
    if (this.timer) return;
    this.timer = setInterval(() => {
      if (this.currentStep < this.totalSteps) {
        this.currentStep++;
        this.render();
      } else {
        this.pause();
      }
    }, this.speed);
  }
  pause() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }
  step() {
    if (this.currentStep < this.totalSteps) {
      this.currentStep++;
      this.render();
    }
  }
  reset() {
    this.pause();
    this.currentStep = 0;
    this.render();
  }
  setSpeed(val) {
    this.speed = val;
  }
  applyCustomData() {
    const input = document.getElementById('custom-input');
    if (input && input.value) {
      this.path = input.value;
      this.reset();
    }
  }
}
